+export async function maybeSeedControlUiAllowedOriginsAtStartup(params: {
+  config: OpenClawConfig;
+  writeConfig: (config: OpenClawConfig) => Promise<void>;
+  log: { info: (msg: string) => void; warn: (msg: string) => void };
